#include <bits/stdc++.h>
using namespace std;
const int N=200005; 
long long a[N],n,q,s,t,f[N],ans;
long long fun(long long x)
{
	if(x>0) return -s*x;
	else return -t*x;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q>>s>>t>>a[0];
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		f[i]=a[i]-a[i-1];
		ans+=fun(f[i]);
	}
	for(int i=1;i<=q;i++)
	{
		int x,y,z;
		cin>>x>>y>>z;
		//s x +z,s y+1 -z
		ans+=(fun(f[x]+z)-fun(f[x]));
		if(y!=n) ans+=(fun(f[y+1]-z)-fun(f[y+1]));
		cout<<ans<<'\n';
		f[x]+=z;
		f[y+1]-=z;
	}
	return 0;
}
